import React, { useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { User } from '../types';
import { 
  Mail, Lock, ShieldCheck, User as UserIcon, 
  Briefcase, Loader2, Terminal, AlertTriangle, 
  ChevronDown, Eye, EyeOff, Search
} from 'lucide-react';
import { PREDEFINED_ACCOUNTS } from '../constants';

interface LoginProps {
  onLogin: (user: User) => void;
  onLocalBypass: (user: User) => void;
}

const Login: React.FC<LoginProps> = ({ onLogin }) => {
  const [isLoginMode, setIsLoginMode] = useState(true);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [fullName, setFullName] = useState('');
  const [studentLrn, setStudentLrn] = useState('');
  const [role, setRole] = useState<'Teacher' | 'Counselor' | 'Parent'>('Teacher');
  const [error, setError] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [showPassword, setShowPassword] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setError('');

    try {
      if (isLoginMode) {
        const predefined = PREDEFINED_ACCOUNTS.find(a => a.email === email && a.password === password);
        if (predefined) {
          onLogin(predefined.user as User);
          return;
        }

        const { data: authData, error: authError } = await supabase.auth.signInWithPassword({ email, password });
        if (authError) throw authError;

        if (authData.user) {
          const { data: profile } = await supabase.from('profiles').select('*').eq('id', authData.user.id).single();
          if (profile) onLogin(profile as User);
          else onLogin({ id: authData.user.id, full_name: 'Verified User', role: 'Teacher', email: authData.user.email!, username: 'user', is_active: true } as User);
        }
      } else {
        // Parent validation: Ensure LRN exists if signing up as parent
        if (role === 'Parent' && studentLrn.length < 5) {
          throw new Error("A valid Student LRN is required for Parent registration.");
        }

        const { data: signUpData, error: signUpError } = await supabase.auth.signUp({
          email,
          password,
          options: { 
            data: { 
              full_name: fullName, 
              role: role,
              linked_lrn: role === 'Parent' ? studentLrn : null
            },
            emailRedirectTo: window.location.origin
          }
        });

        if (signUpError) throw signUpError;

        if (signUpData.user) {
          alert("Verification email sent! Please confirm your email to activate your registry access.");
          setIsLoginMode(true);
        }
      }
    } catch (err: any) {
      setError(err.message || 'Verification system failure.');
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-slate-50 relative overflow-hidden p-4">
      <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-teal-500 via-slate-900 to-teal-500"></div>

      <div className="w-full max-w-md relative z-10 space-y-4">
        <div className="bg-white rounded-2xl shadow-2xl border border-slate-200 overflow-hidden">
          <div className="px-6 py-2.5 bg-slate-900 flex items-center justify-between">
            <div className="flex items-center gap-2">
              <div className="w-2 h-2 rounded-full bg-teal-400 shadow-[0_0_8px_currentColor]"></div>
              <span className="text-[10px] font-black text-white/80 uppercase tracking-widest">Registry Secure</span>
            </div>
            <Terminal size={12} className="text-white/40" />
          </div>

          <div className="p-10 pb-6 text-center">
            <div className="w-16 h-16 bg-slate-900 rounded-2xl flex items-center justify-center text-white mx-auto mb-6 shadow-2xl ring-4 ring-slate-50">
              <ShieldCheck size={32} />
            </div>
            <h1 className="text-3xl font-bold text-slate-900 tracking-tight">SAFE-EDU</h1>
            <p className="text-slate-500 text-[10px] font-black uppercase tracking-widest mt-2">Family & Scholar Access Portal</p>
          </div>

          <div className="px-10 flex border-b border-slate-100">
            <button onClick={() => setIsLoginMode(true)} className={`flex-1 py-4 text-[10px] font-black uppercase tracking-widest transition-all ${isLoginMode ? 'text-slate-900 border-b-2 border-slate-900' : 'text-slate-400 hover:text-slate-600'}`}>Sign In</button>
            <button onClick={() => setIsLoginMode(false)} className={`flex-1 py-4 text-[10px] font-black uppercase tracking-widest transition-all ${!isLoginMode ? 'text-slate-900 border-b-2 border-slate-900' : 'text-slate-400 hover:text-slate-600'}`}>Register</button>
          </div>

          <form onSubmit={handleSubmit} className="p-10 pt-8 pb-12 space-y-4">
            {error && <div className="p-3 bg-red-50 text-red-600 text-[10px] font-bold uppercase rounded-lg border border-red-100 flex items-center gap-2 animate-pulse"><AlertTriangle size={14}/> {error}</div>}

            <div className="space-y-4">
              {!isLoginMode && (
                <>
                  <div className="relative">
                    <UserIcon className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                    <input required type="text" value={fullName} onChange={(e) => setFullName(e.target.value)} className="w-full pl-10 pr-4 py-3.5 bg-slate-50 border border-slate-200 rounded-xl text-sm outline-none focus:ring-1 focus:ring-slate-900 font-medium" placeholder="Full Name" />
                  </div>
                  <div className="relative group">
                    <Briefcase className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" size={16} />
                    <select 
                      value={role} 
                      onChange={(e) => setRole(e.target.value as any)} 
                      className="w-full pl-10 pr-10 py-3.5 bg-slate-50 border border-slate-200 rounded-xl text-sm outline-none focus:ring-1 focus:ring-slate-900 appearance-none font-bold uppercase tracking-widest cursor-pointer"
                    >
                      <option value="Teacher">Teacher</option>
                      <option value="Counselor">Counselor</option>
                      <option value="Parent">Parent / Guardian</option>
                    </select>
                    <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" size={16} />
                  </div>
                  {role === 'Parent' && (
                    <div className="relative animate-in slide-in-from-top-2">
                      <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-teal-500" size={16} />
                      <input required type="text" value={studentLrn} onChange={(e) => setStudentLrn(e.target.value)} className="w-full pl-10 pr-4 py-3.5 bg-teal-50 border border-teal-200 rounded-xl text-sm outline-none focus:ring-1 focus:ring-teal-600 font-bold placeholder:text-teal-300" placeholder="Student LRN (Child's ID)" />
                      <p className="text-[8px] text-teal-600 font-bold uppercase tracking-widest mt-1 ml-1">Required to link your child's records</p>
                    </div>
                  )}
                </>
              )}
              <div className="relative">
                <Mail className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                <input required type="email" value={email} onChange={(e) => setEmail(e.target.value)} className="w-full pl-10 pr-4 py-3.5 bg-slate-50 border border-slate-200 rounded-xl text-sm outline-none focus:ring-1 focus:ring-slate-900 font-medium" placeholder="Email Address" />
              </div>
              <div className="relative">
                <Lock className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                <input required type={showPassword ? "text" : "password"} value={password} onChange={(e) => setPassword(e.target.value)} className="w-full pl-10 pr-10 py-3.5 bg-slate-50 border border-slate-200 rounded-xl text-sm outline-none focus:ring-1 focus:ring-slate-900 font-medium" placeholder="Password" />
                <button type="button" onClick={() => setShowPassword(!showPassword)} className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 hover:text-slate-600 transition-colors">
                  {showPassword ? <EyeOff size={16} /> : <Eye size={16} />}
                </button>
              </div>
            </div>

            <button type="submit" disabled={isLoading} className="w-full py-4 bg-slate-900 text-white rounded-xl font-black text-[10px] uppercase shadow-2xl active:scale-95 disabled:opacity-70 transition-all hover:bg-slate-800 tracking-[0.2em]">
              {isLoading ? <Loader2 size={18} className="animate-spin mx-auto" /> : isLoginMode ? 'Enter Registry' : 'Confirm Identity'}
            </button>
            {isLoginMode && (
              <button type="button" className="w-full text-[9px] font-black uppercase text-slate-400 tracking-widest hover:text-slate-600 transition-colors">Forgot Password?</button>
            )}
          </form>
        </div>
      </div>
    </div>
  );
};

export default Login;

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { Loader2, AlertCircle } from 'lucide-react';
import Layout from './components/Layout';
import Dashboard from './pages/Dashboard';
import Students from './pages/Students';
import Incidents from './pages/Incidents';
import Interventions from './pages/Interventions';
import UserManagement from './pages/UserManagement';
import Reports from './pages/Reports';
import SystemLogs from './pages/SystemLogs';
import Login from './pages/Login';
import { User, Incident, Student, BehavioralIntervention, DeviceUsageRecord, ParentGuardian, GeneratedReport, Notification, SystemLog, IncidentType } from './types';
import { supabase } from './services/supabaseClient';
import { 
  MOCK_STUDENTS, MOCK_INCIDENTS, MOCK_INCIDENT_TYPES, 
  MOCK_INTERVENTIONS, MOCK_DEVICE_LOGS, MOCK_PARENTS, 
  MOCK_REPORTS, MOCK_SYSTEM_LOGS, MOCK_NOTIFICATIONS,
  PREDEFINED_ACCOUNTS
} from './constants';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState('Dashboard');
  const [isInitializing, setIsInitializing] = useState(true);
  const [localMode, setLocalMode] = useState(false);

  const [allIncidents, setAllIncidents] = useState<Incident[]>([]);
  const [incidentTypes, setIncidentTypes] = useState<IncidentType[]>([]);
  const [allStudents, setAllStudents] = useState<Student[]>([]);
  const [interventions, setInterventions] = useState<BehavioralIntervention[]>([]);
  const [deviceLogs, setDeviceLogs] = useState<DeviceUsageRecord[]>([]);
  const [parents, setParents] = useState<ParentGuardian[]>([]);
  const [reports, setReports] = useState<GeneratedReport[]>([]);
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [systemLogs, setSystemLogs] = useState<SystemLog[]>([]);
  const [searchQuery, setSearchQuery] = useState('');

  // PRIVACY LAYER: Filter data for parents
  const parentRecord = useMemo(() => {
    if (currentUser?.role !== 'Parent') return null;
    return parents.find(p => p.user_id === currentUser.id) || MOCK_PARENTS[0];
  }, [currentUser, parents]);

  const filteredStudents = useMemo(() => {
    if (currentUser?.role === 'Parent' && parentRecord) {
      return allStudents.filter(s => s.id === parentRecord.student_id);
    }
    return allStudents;
  }, [currentUser, allStudents, parentRecord]);

  const filteredIncidents = useMemo(() => {
    if (currentUser?.role === 'Parent' && parentRecord) {
      return allIncidents.filter(inc => inc.student_id === parentRecord.student_id);
    }
    return allIncidents;
  }, [currentUser, allIncidents, parentRecord]);

  const addSystemLog = useCallback(async (action: string, category: SystemLog['category']) => {
    if (!currentUser) return;
    const newLog: SystemLog = {
      id: `sl-${Date.now()}`,
      timestamp: new Date().toISOString(),
      user_id: currentUser.id,
      user_name: currentUser.full_name,
      action,
      category,
      ip_address: 'Registry-Access'
    };
    setSystemLogs(prev => [newLog, ...prev]);
  }, [currentUser]);

  const fetchRegistryData = useCallback(async () => {
    setAllStudents(MOCK_STUDENTS);
    setAllIncidents(MOCK_INCIDENTS);
    setIncidentTypes(MOCK_INCIDENT_TYPES);
    setInterventions(MOCK_INTERVENTIONS);
    setDeviceLogs(MOCK_DEVICE_LOGS);
    setParents(MOCK_PARENTS);
    setReports(MOCK_REPORTS);
    setSystemLogs(MOCK_SYSTEM_LOGS);
    setNotifications(MOCK_NOTIFICATIONS);
    setIsInitializing(false);
  }, []);

  useEffect(() => {
    if (currentUser) {
      fetchRegistryData();
    } else {
      setIsInitializing(false);
    }
  }, [currentUser, fetchRegistryData]);

  const handleLogout = () => {
    setCurrentUser(null);
    setActiveTab('Dashboard');
  };

  const handleAddIncident = useCallback(async (newInc: Partial<Incident>) => {
    const incData: Incident = {
      id: `i-${Date.now()}`,
      student_id: newInc.student_id!,
      reported_by_user_id: currentUser!.id,
      incident_type_id: newInc.incident_type_id!,
      date_reported: new Date().toISOString(),
      date_occurred: newInc.date_occurred || new Date().toISOString(),
      location: newInc.location!,
      description: newInc.description!,
      immediate_action: newInc.immediate_action || 'Registry Entry',
      status: 'Pending',
      is_parent_reported: currentUser?.role === 'Parent',
      is_anonymous: newInc.is_anonymous || false
    };

    setAllIncidents(prev => [incData, ...prev]);
    addSystemLog(`Incident Recorded by ${currentUser?.role}`, 'Registry');

    if (currentUser?.role === 'Parent') {
      alert("Thank you. Your report has been submitted and will be reviewed.");
    }
  }, [currentUser, addSystemLog]);

  const handleUpdateStatus = useCallback(async (id: string, status: Incident['status']) => {
    setAllIncidents(prev => prev.map(inc => inc.id === id ? { ...inc, status } : inc));
  }, []);

  const renderContent = () => {
    if (!currentUser) return null;
    switch (activeTab) {
      case 'Dashboard': return <Dashboard incidents={filteredIncidents} students={filteredStudents} deviceLogs={deviceLogs} />;
      case 'Students': return <Students currentUser={currentUser} incidents={filteredIncidents} students={filteredStudents} searchQuery={searchQuery} parents={parents} deviceLogs={deviceLogs} onAddStudent={async() => {}} />;
      case 'Incidents': return <Incidents currentUser={currentUser} incidents={filteredIncidents} students={filteredStudents} incidentTypes={incidentTypes} onAddIncident={handleAddIncident} onUpdateStatus={handleUpdateStatus} searchQuery={searchQuery} />;
      case 'Interventions': return <Interventions currentUser={currentUser} students={filteredStudents} interventions={interventions} onAddIntervention={() => {}} />;
      case 'Reports': return <Reports currentUser={currentUser} reports={reports} onGenerateReport={() => {}} />;
      case 'System Logs': return <SystemLogs logs={systemLogs} />;
      case 'User Management': return <UserManagement localUsers={[]} onUpdateUser={() => {}} onSync={async() => {}} />;
      default: return <Dashboard incidents={filteredIncidents} students={filteredStudents} deviceLogs={deviceLogs} />;
    }
  };

  if (isInitializing) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-slate-50">
        <Loader2 className="animate-spin text-slate-900" />
      </div>
    );
  }

  if (!currentUser) return <Login onLogin={setCurrentUser} onLocalBypass={() => {}} />;

  return (
    <Layout user={currentUser} activeTab={activeTab} setActiveTab={setActiveTab} onLogout={handleLogout} searchQuery={searchQuery} setSearchQuery={setSearchQuery} notifications={notifications} onMarkRead={() => {}}>
      {renderContent()}
    </Layout>
  );
};

export default App;

import React, { useMemo, useState, useRef } from 'react';
import { AlertTriangle, Plus, Eye, X, ShieldCheck, Mic, MicOff, Loader2, BrainCircuit, Shield } from 'lucide-react';
import { User, Incident, Student, IncidentType } from '../types';
import { GoogleGenAI } from "@google/genai";

interface IncidentsProps {
  currentUser: User;
  incidents: Incident[];
  students: Student[];
  incidentTypes: IncidentType[];
  onAddIncident: (inc: Partial<Incident>) => void;
  onUpdateStatus: (id: string, status: Incident['status']) => void;
  searchQuery: string;
}

const Incidents: React.FC<IncidentsProps> = ({ currentUser, incidents, students, incidentTypes, onAddIncident, onUpdateStatus, searchQuery }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isDictating, setIsDictating] = useState(false);
  const [isProcessingAI, setIsProcessingAI] = useState(false);
  const [newIncident, setNewIncident] = useState({ 
    student_id: currentUser.role === 'Parent' ? students[0]?.id : '', 
    incident_type_id: '', 
    location: '', 
    description: '', 
    immediate_action: '',
    date_occurred: new Date().toISOString().split('T')[0],
    is_anonymous: false
  });

  const recognitionRef = useRef<any>(null);

  const visibleIncidents = useMemo(() => {
    let filtered = [...incidents];
    if (searchQuery) {
      const q = searchQuery.toLowerCase();
      filtered = filtered.filter(inc => {
        const s = students.find(st => st.id === inc.student_id);
        return (
          s?.first_name.toLowerCase().includes(q) || 
          inc.description.toLowerCase().includes(q)
        );
      });
    }
    return filtered;
  }, [incidents, searchQuery, students]);

  const toggleDictation = () => {
    if (isDictating) {
      recognitionRef.current?.stop();
      setIsDictating(false);
    } else {
      const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
      if (!SpeechRecognition) return;
      recognitionRef.current = new SpeechRecognition();
      recognitionRef.current.continuous = true;
      recognitionRef.current.onresult = (event: any) => {
        const transcript = event.results[event.results.length - 1][0].transcript;
        setNewIncident(prev => ({ ...prev, description: prev.description + transcript }));
      };
      recognitionRef.current.start();
      setIsDictating(true);
    }
  };

  const handleAiRefinement = async () => {
    if (!newIncident.description) return;
    setIsProcessingAI(true);
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Rewrite this behavioral observation into a professional, objective incident report: "${newIncident.description}"`
      });
      if (response.text) setNewIncident(prev => ({ ...prev, description: response.text }));
    } catch (e) {
      console.error(e);
    } finally {
      setIsProcessingAI(false);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onAddIncident(newIncident);
    setIsModalOpen(false);
    setNewIncident({ 
      student_id: currentUser.role === 'Parent' ? students[0]?.id : '', 
      incident_type_id: '', 
      location: '', 
      description: '', 
      immediate_action: '',
      date_occurred: new Date().toISOString().split('T')[0],
      is_anonymous: false
    });
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-700">
      <div className="flex flex-col md:flex-row justify-between md:items-end gap-6 border-b border-slate-200 pb-8">
        <div>
          <h2 className="text-3xl font-bold text-slate-900 tracking-tight">
            {currentUser.role === 'Parent' ? 'Welfare History' : 'Assistance Records'}
          </h2>
          <p className="text-slate-500 font-medium">
            {currentUser.role === 'Parent' ? 'Tracking events and safety updates for your child.' : 'Official registry for behavioral monitoring.'}
          </p>
        </div>
        <button onClick={() => setIsModalOpen(true)} className="flex items-center gap-2 bg-slate-900 text-white px-5 py-2.5 rounded-lg font-bold text-xs uppercase tracking-widest hover:bg-slate-800 transition-all shadow-xl active:scale-95">
          <Plus size={16} /> {currentUser.role === 'Parent' ? 'Report a Concern' : 'Report New Event'}
        </button>
      </div>

      <div className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="overflow-x-auto scrollbar-hide">
          <table className="w-full text-left min-w-[800px]">
            <thead className="bg-slate-50/50">
              <tr>
                <th className="px-8 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Event Nature</th>
                <th className="px-8 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Subject</th>
                <th className="px-8 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Occurrence Date</th>
                <th className="px-8 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Registry Status</th>
                <th className="px-8 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {visibleIncidents.map((inc) => {
                const student = students.find(s => s.id === inc.student_id);
                const type = incidentTypes.find(t => t.id === inc.incident_type_id);
                return (
                  <tr key={inc.id} className="hover:bg-slate-50/50 transition-all">
                    <td className="px-8 py-5">
                      <div className="flex items-center gap-2">
                        <p className="text-sm font-bold text-slate-900">{type?.name || 'Behavioral Report'}</p>
                        {inc.is_parent_reported && <span className="text-[8px] px-1.5 py-0.5 bg-blue-50 text-blue-600 font-black uppercase rounded border border-blue-100">Parent Report</span>}
                      </div>
                      <p className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter truncate max-w-xs">{inc.description}</p>
                    </td>
                    <td className="px-8 py-5 text-sm font-bold text-slate-800">{student ? `${student.first_name} ${student.last_name}` : 'N/A'}</td>
                    <td className="px-8 py-5 text-xs font-bold text-slate-500">{new Date(inc.date_occurred).toLocaleDateString()}</td>
                    <td className="px-8 py-5">
                      <div className={`inline-flex items-center gap-2 px-3 py-1.5 rounded text-[10px] font-black uppercase tracking-widest border ${
                        inc.status === 'Resolved' ? 'bg-teal-50 text-teal-700 border-teal-100' : 'bg-amber-50 text-amber-700 border-amber-100'
                      }`}>
                        {inc.status}
                      </div>
                    </td>
                    <td className="px-8 py-5 text-right"><Eye size={16} className="ml-auto text-slate-300 hover:text-slate-900 cursor-pointer" /></td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
          <div className="bg-white rounded-xl shadow-2xl w-full max-w-lg overflow-hidden animate-in zoom-in-95">
            <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50">
              <div className="flex items-center gap-2">
                <ShieldCheck size={18} className="text-teal-600" />
                <h3 className="text-sm font-black text-slate-800 uppercase tracking-widest">
                  {currentUser.role === 'Parent' ? 'Submit Welfare Concern' : 'Official Event Entry'}
                </h3>
              </div>
              <button onClick={() => setIsModalOpen(false)}><X size={20} /></button>
            </div>
            <form onSubmit={handleSubmit} className="p-6 space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Target Subject</label>
                  <select disabled={currentUser.role === 'Parent'} required value={newIncident.student_id} onChange={(e) => setNewIncident({...newIncident, student_id: e.target.value})} className="w-full bg-slate-50 border border-slate-200 rounded-lg px-3 py-2 text-sm outline-none">
                    {currentUser.role === 'Parent' ? (
                      <option value={students[0]?.id}>{students[0]?.first_name} {students[0]?.last_name}</option>
                    ) : (
                      <>
                        <option value="">Select Student</option>
                        {students.map(s => <option key={s.id} value={s.id}>{s.last_name}, {s.first_name}</option>)}
                      </>
                    )}
                  </select>
                </div>
                <div>
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Nature</label>
                  <select required value={newIncident.incident_type_id} onChange={(e) => setNewIncident({...newIncident, incident_type_id: e.target.value})} className="w-full bg-slate-50 border border-slate-200 rounded-lg px-3 py-2 text-sm outline-none">
                    <option value="">Select Category</option>
                    {incidentTypes.map(t => <option key={t.id} value={t.id}>{t.name}</option>)}
                  </select>
                </div>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Occurrence Date</label>
                  <input required type="date" value={newIncident.date_occurred} onChange={(e) => setNewIncident({...newIncident, date_occurred: e.target.value})} className="w-full bg-slate-50 border border-slate-200 rounded-lg px-3 py-2 text-sm outline-none" />
                </div>
                <div>
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Location</label>
                  <input required type="text" value={newIncident.location} onChange={(e) => setNewIncident({...newIncident, location: e.target.value})} className="w-full bg-slate-50 border border-slate-200 rounded-lg px-3 py-2 text-sm outline-none" placeholder="e.g. Science Lab" />
                </div>
              </div>

              <div className="relative">
                <div className="flex justify-between items-center mb-1">
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">Description</label>
                  <div className="flex gap-2">
                    <button type="button" onClick={handleAiRefinement} className="text-[9px] font-black uppercase text-teal-600 flex items-center gap-1">
                      {isProcessingAI ? <Loader2 size={10} className="animate-spin" /> : <BrainCircuit size={10} />} AI Clear
                    </button>
                    <button type="button" onClick={toggleDictation} className={`p-1.5 rounded-full ${isDictating ? 'bg-red-500 text-white animate-pulse' : 'bg-slate-100 text-slate-500'}`}>
                      {isDictating ? <MicOff size={12} /> : <Mic size={12} />}
                    </button>
                  </div>
                </div>
                <textarea required value={newIncident.description} onChange={(e) => setNewIncident({...newIncident, description: e.target.value})} className="w-full bg-slate-50 border border-slate-200 rounded-lg px-3 py-2 text-sm min-h-[100px] outline-none" placeholder="Provide clear event details..." />
              </div>

              <div className="flex items-center gap-2 py-2">
                <input type="checkbox" checked={newIncident.is_anonymous} onChange={(e) => setNewIncident({...newIncident, is_anonymous: e.target.checked})} className="w-4 h-4 text-teal-600 bg-slate-100 border-slate-300 rounded focus:ring-teal-500" />
                <label className="text-[10px] font-bold text-slate-600 uppercase tracking-widest flex items-center gap-1">
                  <Shield size={10} /> Submit Anonymously
                </label>
              </div>

              <button type="submit" className="w-full bg-slate-900 text-white py-4 rounded-lg text-xs font-black uppercase tracking-widest shadow-xl active:scale-95">
                {currentUser.role === 'Parent' ? 'Confirm Report Submission' : 'Commit Entry to Registry'}
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Incidents;

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { Loader2, AlertCircle } from 'lucide-react';
import Layout from './components/Layout';
import Dashboard from './pages/Dashboard';
import Students from './pages/Students';
import Incidents from './pages/Incidents';
import Interventions from './pages/Interventions';
import UserManagement from './pages/UserManagement';
import Reports from './pages/Reports';
import SystemLogs from './pages/SystemLogs';
import Login from './pages/Login';
import { User, Incident, Student, BehavioralIntervention, DeviceUsageRecord, ParentGuardian, GeneratedReport, Notification, SystemLog, IncidentType } from './types';
import { supabase } from './services/supabaseClient';
import { 
  MOCK_STUDENTS, MOCK_INCIDENTS, MOCK_INCIDENT_TYPES, 
  MOCK_INTERVENTIONS, MOCK_DEVICE_LOGS, MOCK_PARENTS, 
  MOCK_REPORTS, MOCK_SYSTEM_LOGS, MOCK_NOTIFICATIONS
} from './constants';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState('Dashboard');
  const [isInitializing, setIsInitializing] = useState(true);

  const [allIncidents, setAllIncidents] = useState<Incident[]>([]);
  const [incidentTypes, setIncidentTypes] = useState<IncidentType[]>([]);
  const [allStudents, setAllStudents] = useState<Student[]>([]);
  const [interventions, setInterventions] = useState<BehavioralIntervention[]>([]);
  const [deviceLogs, setDeviceLogs] = useState<DeviceUsageRecord[]>([]);
  const [parents, setParents] = useState<ParentGuardian[]>([]);
  const [reports, setReports] = useState<GeneratedReport[]>([]);
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [systemLogs, setSystemLogs] = useState<SystemLog[]>([]);
  const [searchQuery, setSearchQuery] = useState('');

  // PRIVACY LAYER: Filter data for parents
  const parentRecord = useMemo(() => {
    if (currentUser?.role !== 'Parent') return null;
    return parents.find(p => p.user_id === currentUser.id);
  }, [currentUser, parents]);

  const filteredStudents = useMemo(() => {
    if (currentUser?.role === 'Parent' && parentRecord) {
      return allStudents.filter(s => s.id === parentRecord.student_id);
    }
    return allStudents;
  }, [currentUser, allStudents, parentRecord]);

  const filteredIncidents = useMemo(() => {
    if (currentUser?.role === 'Parent' && parentRecord) {
      return allIncidents.filter(inc => inc.student_id === parentRecord.student_id);
    }
    return allIncidents;
  }, [currentUser, allIncidents, parentRecord]);

  const addSystemLog = useCallback(async (action: string, category: SystemLog['category']) => {
    if (!currentUser) return;
    const newLog = {
      user_id: currentUser.id,
      user_name: currentUser.full_name,
      action,
      category,
      ip_address: 'Registry-Access',
      timestamp: new Date().toISOString()
    };

    // Save to Supabase
    await supabase.from('system_audit_logs').insert([newLog]);

    // Local update for immediate UI feedback
    setSystemLogs(prev => [{ ...newLog, id: `sl-${Date.now()}` } as SystemLog, ...prev]);
  }, [currentUser]);

  const fetchRegistryData = useCallback(async () => {
    try {
      // Parallel fetching from Supabase
      const [
        { data: studentsData },
        { data: incidentsData },
        { data: typesData },
        { data: interventionsData },
        { data: logsData },
        { data: parentsData },
        { data: reportsData },
        { data: sysLogsData },
        { data: notifsData }
      ] = await Promise.all([
        supabase.from('students').select('*'),
        supabase.from('incidents').select('*').order('date_reported', { ascending: false }),
        supabase.from('incident_types').select('*'),
        supabase.from('interventions').select('*'),
        supabase.from('device_logs').select('*'),
        supabase.from('parents').select('*'),
        supabase.from('generated_reports').select('*'),
        supabase.from('system_audit_logs').select('*').order('timestamp', { ascending: false }),
        supabase.from('notifications').select('*').order('timestamp', { ascending: false })
      ]);

      // Use database data or fall back to mock if tables are empty/unreachable
      setAllStudents(studentsData?.length ? studentsData : MOCK_STUDENTS);
      setAllIncidents(incidentsData?.length ? incidentsData : MOCK_INCIDENTS);
      setIncidentTypes(typesData?.length ? typesData : MOCK_INCIDENT_TYPES);
      setInterventions(interventionsData?.length ? interventionsData : MOCK_INTERVENTIONS);
      setDeviceLogs(logsData?.length ? logsData : MOCK_DEVICE_LOGS);
      setParents(parentsData?.length ? parentsData : MOCK_PARENTS);
      setReports(reportsData?.length ? reportsData : MOCK_REPORTS);
      setSystemLogs(sysLogsData?.length ? sysLogsData : MOCK_SYSTEM_LOGS);
      setNotifications(notifsData?.length ? notifsData : MOCK_NOTIFICATIONS);
    } catch (err) {
      console.error("Critical: Registry synchronization failed.", err);
    } finally {
      setIsInitializing(false);
    }
  }, []);

  useEffect(() => {
    const checkUser = async () => {
      const { data: { session } } = await supabase.auth.getSession();
      if (session?.user) {
        const { data: profile } = await supabase.from('profiles').select('*').eq('id', session.user.id).single();
        if (profile) setCurrentUser(profile as User);
      }
      setIsInitializing(false);
    };
    checkUser();
  }, []);

  useEffect(() => {
    if (currentUser) {
      fetchRegistryData();
    }
  }, [currentUser, fetchRegistryData]);

  const handleLogout = async () => {
    await supabase.auth.signOut();
    setCurrentUser(null);
    setActiveTab('Dashboard');
  };

  const handleAddIncident = useCallback(async (newInc: Partial<Incident>) => {
    const incData = {
      student_id: newInc.student_id,
      reported_by_user_id: currentUser!.id,
      incident_type_id: newInc.incident_type_id,
      date_reported: new Date().toISOString(),
      date_occurred: newInc.date_occurred || new Date().toISOString(),
      location: newInc.location,
      description: newInc.description,
      immediate_action: newInc.immediate_action || 'Registry Entry',
      status: 'Pending',
      is_parent_reported: currentUser?.role === 'Parent',
      is_anonymous: newInc.is_anonymous || false
    };

    const { data, error } = await supabase.from('incidents').insert([incData]).select();

    if (!error && data) {
      setAllIncidents(prev => [data[0] as Incident, ...prev]);
      addSystemLog(`Incident Registered: ${data[0].id}`, 'Registry');
      if (currentUser?.role === 'Parent') {
        alert("Thank you. Your report has been submitted and will be reviewed.");
      }
    } else {
      console.error("Registry commit failed:", error);
    }
  }, [currentUser, addSystemLog]);

  const handleAddStudent = useCallback(async (studentData: Partial<Student>) => {
    const { data, error } = await supabase.from('students').insert([studentData]).select();
    if (!error && data) {
      setAllStudents(prev => [data[0] as Student, ...prev]);
      addSystemLog(`New Subject Registered: ${data[0].lrn}`, 'Registry');
      return data[0];
    }
    return null;
  }, [addSystemLog]);

  const handleUpdateStatus = useCallback(async (id: string, status: Incident['status']) => {
    const { error } = await supabase.from('incidents').update({ status }).eq('id', id);
    if (!error) {
      setAllIncidents(prev => prev.map(inc => inc.id === id ? { ...inc, status } : inc));
      addSystemLog(`Incident ${id} updated to ${status}`, 'Audit');
    }
  }, [addSystemLog]);

  const renderContent = () => {
    if (!currentUser) return null;
    switch (activeTab) {
      case 'Dashboard': return <Dashboard incidents={filteredIncidents} students={filteredStudents} deviceLogs={deviceLogs} />;
      case 'Students': return <Students currentUser={currentUser} incidents={filteredIncidents} students={filteredStudents} searchQuery={searchQuery} parents={parents} deviceLogs={deviceLogs} onAddStudent={handleAddStudent} />;
      case 'Incidents': return <Incidents currentUser={currentUser} incidents={filteredIncidents} students={filteredStudents} incidentTypes={incidentTypes} onAddIncident={handleAddIncident} onUpdateStatus={handleUpdateStatus} searchQuery={searchQuery} />;
      case 'Interventions': return <Interventions currentUser={currentUser} students={filteredStudents} interventions={interventions} onAddIntervention={(data) => supabase.from('interventions').insert([data])} />;
      case 'Reports': return <Reports currentUser={currentUser} reports={reports} onGenerateReport={(data) => supabase.from('generated_reports').insert([data])} />;
      case 'System Logs': return <SystemLogs logs={systemLogs} />;
      case 'User Management': return <UserManagement localUsers={[]} onUpdateUser={(id, updates) => supabase.from('profiles').update(updates).eq('id', id)} onSync={fetchRegistryData} />;
      default: return <Dashboard incidents={filteredIncidents} students={filteredStudents} deviceLogs={deviceLogs} />;
    }
  };

  if (isInitializing) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-slate-50">
        <div className="text-center space-y-4">
          <Loader2 className="animate-spin text-slate-900 mx-auto" size={32} />
          <p className="text-[10px] font-black uppercase tracking-[0.3em] text-slate-400">Synchronizing Registry...</p>
        </div>
      </div>
    );
  }

  if (!currentUser) return <Login onLogin={setCurrentUser} onLocalBypass={() => {}} />;

  return (
    <Layout user={currentUser} activeTab={activeTab} setActiveTab={setActiveTab} onLogout={handleLogout} searchQuery={searchQuery} setSearchQuery={setSearchQuery} notifications={notifications} onMarkRead={() => {}}>
      {renderContent()}
    </Layout>
  );
};

export default App;

import React, { useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { User } from '../types';
import { 
  Mail, Lock, ShieldCheck, User as UserIcon, 
  Briefcase, Loader2, Terminal, AlertTriangle, 
  ChevronDown, Eye, EyeOff, Search
} from 'lucide-react';
import { PREDEFINED_ACCOUNTS } from '../constants';

interface LoginProps {
  onLogin: (user: User) => void;
  onLocalBypass: (user: User) => void;
}

const Login: React.FC<LoginProps> = ({ onLogin }) => {
  const [isLoginMode, setIsLoginMode] = useState(true);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [fullName, setFullName] = useState('');
  const [studentLrn, setStudentLrn] = useState('');
  const [role, setRole] = useState<'Teacher' | 'Counselor' | 'Parent'>('Teacher');
  const [error, setError] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [showPassword, setShowPassword] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setError('');

    try {
      if (isLoginMode) {
        // First try predefined demos
        const predefined = PREDEFINED_ACCOUNTS.find(a => a.email === email && a.password === password);
        if (predefined) {
          onLogin(predefined.user as User);
          return;
        }

        // Real Supabase Auth
        const { data: authData, error: authError } = await supabase.auth.signInWithPassword({ email, password });
        if (authError) throw authError;

        if (authData.user) {
          const { data: profile } = await supabase.from('profiles').select('*').eq('id', authData.user.id).single();
          if (profile) {
            onLogin(profile as User);
          } else {
            // Fallback for users created without a profile record
            onLogin({ 
              id: authData.user.id, 
              full_name: authData.user.user_metadata.full_name || 'Registry User', 
              role: authData.user.user_metadata.role || 'Teacher', 
              email: authData.user.email!, 
              username: authData.user.email!.split('@')[0], 
              is_active: true 
            } as User);
          }
        }
      } else {
        // Parent validation
        if (role === 'Parent' && studentLrn.length < 5) {
          throw new Error("A valid Student LRN is required for Parent registration.");
        }

        const { data: signUpData, error: signUpError } = await supabase.auth.signUp({
          email,
          password,
          options: { 
            data: { 
              full_name: fullName, 
              role: role,
              linked_lrn: role === 'Parent' ? studentLrn : null
            }
          }
        });

        if (signUpError) throw signUpError;

        if (signUpData.user) {
          // Explicitly create profile to ensure queryability
          await supabase.from('profiles').insert([{
            id: signUpData.user.id,
            full_name: fullName,
            role: role,
            email: email,
            username: email.split('@')[0],
            is_active: true
          }]);

          alert("Verification email sent! Please confirm your email to activate your registry access.");
          setIsLoginMode(true);
        }
      }
    } catch (err: any) {
      setError(err.message || 'Verification system failure.');
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-slate-50 relative overflow-hidden p-4">
      <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-teal-500 via-slate-900 to-teal-500"></div>

      <div className="w-full max-w-md relative z-10 space-y-4">
        <div className="bg-white rounded-2xl shadow-2xl border border-slate-200 overflow-hidden">
          <div className="px-6 py-2.5 bg-slate-900 flex items-center justify-between">
            <div className="flex items-center gap-2">
              <div className="w-2 h-2 rounded-full bg-teal-400 shadow-[0_0_8px_currentColor]"></div>
              <span className="text-[10px] font-black text-white/80 uppercase tracking-widest">Registry Secure</span>
            </div>
            <Terminal size={12} className="text-white/40" />
          </div>

          <div className="p-10 pb-6 text-center">
            <div className="w-16 h-16 bg-slate-900 rounded-2xl flex items-center justify-center text-white mx-auto mb-6 shadow-2xl ring-4 ring-slate-50">
              <ShieldCheck size={32} />
            </div>
            <h1 className="text-3xl font-bold text-slate-900 tracking-tight">SAFE-EDU</h1>
            <p className="text-slate-500 text-[10px] font-black uppercase tracking-widest mt-2">Family & Scholar Access Portal</p>
          </div>

          <div className="px-10 flex border-b border-slate-100">
            <button onClick={() => setIsLoginMode(true)} className={`flex-1 py-4 text-[10px] font-black uppercase tracking-widest transition-all ${isLoginMode ? 'text-slate-900 border-b-2 border-slate-900' : 'text-slate-400 hover:text-slate-600'}`}>Sign In</button>
            <button onClick={() => setIsLoginMode(false)} className={`flex-1 py-4 text-[10px] font-black uppercase tracking-widest transition-all ${!isLoginMode ? 'text-slate-900 border-b-2 border-slate-900' : 'text-slate-400 hover:text-slate-600'}`}>Register</button>
          </div>

          <form onSubmit={handleSubmit} className="p-10 pt-8 pb-12 space-y-4">
            {error && <div className="p-3 bg-red-50 text-red-600 text-[10px] font-bold uppercase rounded-lg border border-red-100 flex items-center gap-2 animate-pulse"><AlertTriangle size={14}/> {error}</div>}

            <div className="space-y-4">
              {!isLoginMode && (
                <>
                  <div className="relative">
                    <UserIcon className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                    <input required type="text" value={fullName} onChange={(e) => setFullName(e.target.value)} className="w-full pl-10 pr-4 py-3.5 bg-slate-50 border border-slate-200 rounded-xl text-sm outline-none focus:ring-1 focus:ring-slate-900 font-medium" placeholder="Full Name" />
                  </div>
                  <div className="relative group">
                    <Briefcase className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" size={16} />
                    <select 
                      value={role} 
                      onChange={(e) => setRole(e.target.value as any)} 
                      className="w-full pl-10 pr-10 py-3.5 bg-slate-50 border border-slate-200 rounded-xl text-sm outline-none focus:ring-1 focus:ring-slate-900 appearance-none font-bold uppercase tracking-widest cursor-pointer"
                    >
                      <option value="Teacher">Teacher</option>
                      <option value="Counselor">Counselor</option>
                      <option value="Parent">Parent / Guardian</option>
                    </select>
                    <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" size={16} />
                  </div>
                  {role === 'Parent' && (
                    <div className="relative animate-in slide-in-from-top-2">
                      <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-teal-500" size={16} />
                      <input required type="text" value={studentLrn} onChange={(e) => setStudentLrn(e.target.value)} className="w-full pl-10 pr-4 py-3.5 bg-teal-50 border border-teal-200 rounded-xl text-sm outline-none focus:ring-1 focus:ring-teal-600 font-bold placeholder:text-teal-300" placeholder="Student LRN (Child's ID)" />
                      <p className="text-[8px] text-teal-600 font-bold uppercase tracking-widest mt-1 ml-1">Required to link your child's records</p>
                    </div>
                  )}
                </>
              )}
              <div className="relative">
                <Mail className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                <input required type="email" value={email} onChange={(e) => setEmail(e.target.value)} className="w-full pl-10 pr-4 py-3.5 bg-slate-50 border border-slate-200 rounded-xl text-sm outline-none focus:ring-1 focus:ring-slate-900 font-medium" placeholder="Email Address" />
              </div>
              <div className="relative">
                <Lock className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                <input required type={showPassword ? "text" : "password"} value={password} onChange={(e) => setPassword(e.target.value)} className="w-full pl-10 pr-10 py-3.5 bg-slate-50 border border-slate-200 rounded-xl text-sm outline-none focus:ring-1 focus:ring-slate-900 font-medium" placeholder="Password" />
                <button type="button" onClick={() => setShowPassword(!showPassword)} className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 hover:text-slate-600 transition-colors">
                  {showPassword ? <EyeOff size={16} /> : <Eye size={16} />}
                </button>
              </div>
            </div>

            <button type="submit" disabled={isLoading} className="w-full py-4 bg-slate-900 text-white rounded-xl font-black text-[10px] uppercase shadow-2xl active:scale-95 disabled:opacity-70 transition-all hover:bg-slate-800 tracking-[0.2em]">
              {isLoading ? <Loader2 size={18} className="animate-spin mx-auto" /> : isLoginMode ? 'Enter Registry' : 'Confirm Identity'}
            </button>
            {isLoginMode && (
              <button type="button" className="w-full text-[9px] font-black uppercase text-slate-400 tracking-widest hover:text-slate-600 transition-colors">Forgot Password?</button>
            )}
          </form>
        </div>
      </div>
    </div>
  );
};

export default Login;

