import { GoogleGenAI, Type } from "@google/genai";

/**
 * Analyze student behavioral history using Gemini 3 Pro.
 * Adheres to strict @google/genai SDK guidelines.
 */
export const getBehavioralInsight = async (studentHistory: any[]) => {
  if (!process.env.API_KEY) {
    console.error("API_KEY environment variable is missing.");
    return fallbackResponse("API Access restricted.");
  }

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    You are an expert educational psychologist. 
    Analyze the following student incident history and provide a professional assessment.

    Student Incident Data:
    ${JSON.stringify(studentHistory)}

    Format your response as a JSON object.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview", // Flash for faster insights
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            analysis: { type: Type.STRING },
            riskLevel: { type: Type.STRING },
            suggestedInterventions: {
              type: Type.ARRAY,
              items: { type: Type.STRING }
            },
            growthFocus: { type: Type.STRING }
          },
          required: ["analysis", "riskLevel", "suggestedInterventions", "growthFocus"]
        }
      }
    });

    const resultText = response.text || "{}";
    return JSON.parse(resultText);
  } catch (error) {
    console.error("Gemini Analysis Error:", error);
    return fallbackResponse("Automated analysis failed. Manual review of case logs is required.");
  }
};

const fallbackResponse = (msg: string) => ({
  analysis: msg,
  riskLevel: "Undetermined",
  suggestedInterventions: ["Verify primary student contact details.", "Schedule observation period."],
  growthFocus: "General self-regulation focus recommended."
});

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { Loader2, AlertCircle } from 'lucide-react';
import Layout from './components/Layout';
import Dashboard from './pages/Dashboard';
import Students from './pages/Students';
import Incidents from './pages/Incidents';
import Interventions from './pages/Interventions';
import UserManagement from './pages/UserManagement';
import Reports from './pages/Reports';
import SystemLogs from './pages/SystemLogs';
import Login from './pages/Login';
import { User, Incident, Student, BehavioralIntervention, DeviceUsageRecord, ParentGuardian, GeneratedReport, Notification, SystemLog, IncidentType } from './types';
import { supabase } from './services/supabaseClient';
import { 
  MOCK_STUDENTS, MOCK_INCIDENTS, MOCK_INCIDENT_TYPES, 
  MOCK_INTERVENTIONS, MOCK_DEVICE_LOGS, MOCK_PARENTS, 
  MOCK_REPORTS, MOCK_SYSTEM_LOGS, MOCK_NOTIFICATIONS
} from './constants';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState('Dashboard');
  const [isInitializing, setIsInitializing] = useState(true);

  const [allIncidents, setAllIncidents] = useState<Incident[]>([]);
  const [incidentTypes, setIncidentTypes] = useState<IncidentType[]>([]);
  const [allStudents, setAllStudents] = useState<Student[]>([]);
  const [interventions, setInterventions] = useState<BehavioralIntervention[]>([]);
  const [deviceLogs, setDeviceLogs] = useState<DeviceUsageRecord[]>([]);
  const [parents, setParents] = useState<ParentGuardian[]>([]);
  const [reports, setReports] = useState<GeneratedReport[]>([]);
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [systemLogs, setSystemLogs] = useState<SystemLog[]>([]);
  const [searchQuery, setSearchQuery] = useState('');

  // DATA ISOLATION LOGIC
  const filteredStudents = useMemo(() => {
    if (currentUser?.role === 'Parent' && currentUser.linked_lrn) {
      return allStudents.filter(s => s.lrn === currentUser.linked_lrn);
    }
    return allStudents;
  }, [currentUser, allStudents]);

  const filteredIncidents = useMemo(() => {
    if (currentUser?.role === 'Parent' && filteredStudents.length > 0) {
      const studentId = filteredStudents[0].id;
      return allIncidents.filter(inc => inc.student_id === studentId);
    }
    return allIncidents;
  }, [currentUser, allIncidents, filteredStudents]);

  const addSystemLog = useCallback(async (action: string, category: SystemLog['category']) => {
    if (!currentUser) return;
    const newLog = {
      user_id: currentUser.id,
      user_name: currentUser.full_name,
      action,
      category,
      ip_address: 'Registry-Access',
      timestamp: new Date().toISOString()
    };

    await supabase.from('system_audit_logs').insert([newLog]);
    setSystemLogs(prev => [{ ...newLog, id: `sl-${Date.now()}` } as SystemLog, ...prev]);
  }, [currentUser]);

  const fetchRegistryData = useCallback(async () => {
    try {
      const [
        { data: studentsData },
        { data: incidentsData },
        { data: typesData },
        { data: interventionsData },
        { data: logsData },
        { data: parentsData },
        { data: reportsData },
        { data: sysLogsData },
        { data: notifsData }
      ] = await Promise.all([
        supabase.from('students').select('*'),
        supabase.from('incidents').select('*').order('date_reported', { ascending: false }),
        supabase.from('incident_types').select('*'),
        supabase.from('interventions').select('*'),
        supabase.from('device_logs').select('*'),
        supabase.from('parents').select('*'),
        supabase.from('generated_reports').select('*'),
        supabase.from('system_audit_logs').select('*').order('timestamp', { ascending: false }),
        supabase.from('notifications').select('*').order('timestamp', { ascending: false })
      ]);

      setAllStudents(studentsData?.length ? studentsData : MOCK_STUDENTS);
      setAllIncidents(incidentsData?.length ? incidentsData : MOCK_INCIDENTS);
      setIncidentTypes(typesData?.length ? typesData : MOCK_INCIDENT_TYPES);
      setInterventions(interventionsData?.length ? interventionsData : MOCK_INTERVENTIONS);
      setDeviceLogs(logsData?.length ? logsData : MOCK_DEVICE_LOGS);
      setParents(parentsData?.length ? parentsData : MOCK_PARENTS);
      setReports(reportsData?.length ? reportsData : MOCK_REPORTS);
      setSystemLogs(sysLogsData?.length ? sysLogsData : MOCK_SYSTEM_LOGS);
      setNotifications(notifsData?.length ? notifsData : MOCK_NOTIFICATIONS);
    } catch (err) {
      console.error("Critical: Registry synchronization failed.", err);
    } finally {
      setIsInitializing(false);
    }
  }, []);

  useEffect(() => {
    const checkUser = async () => {
      const { data: { session } } = await supabase.auth.getSession();
      if (session?.user) {
        const { data: profile } = await supabase.from('profiles').select('*').eq('id', session.user.id).single();
        if (profile) setCurrentUser(profile as User);
        else {
          // If no profile, user is probably a demo or just signed up
          setCurrentUser({
            id: session.user.id,
            full_name: session.user.user_metadata.full_name || 'Registry User',
            role: session.user.user_metadata.role || 'Teacher',
            email: session.user.email!,
            username: session.user.email!.split('@')[0],
            is_active: true,
            linked_lrn: session.user.user_metadata.linked_lrn
          });
        }
      }
      setIsInitializing(false);
    };
    checkUser();
  }, []);

  useEffect(() => {
    if (currentUser) {
      fetchRegistryData();
    }
  }, [currentUser, fetchRegistryData]);

  const handleLogout = async () => {
    await supabase.auth.signOut();
    setCurrentUser(null);
    setActiveTab('Dashboard');
  };

  const handleAddIncident = useCallback(async (newInc: Partial<Incident>) => {
    const incData = {
      student_id: newInc.student_id,
      reported_by_user_id: currentUser!.id,
      incident_type_id: newInc.incident_type_id,
      date_reported: new Date().toISOString(),
      date_occurred: newInc.date_occurred || new Date().toISOString(),
      location: newInc.location,
      description: newInc.description,
      immediate_action: newInc.immediate_action || 'Registry Entry',
      status: 'Pending',
      is_parent_reported: currentUser?.role === 'Parent',
      is_anonymous: newInc.is_anonymous || false
    };

    const { data, error } = await supabase.from('incidents').insert([incData]).select();

    if (!error && data) {
      setAllIncidents(prev => [data[0] as Incident, ...prev]);
      addSystemLog(`Incident Registered: ${data[0].id}`, 'Registry');
      if (currentUser?.role === 'Parent') {
        alert("Thank you. Your report has been submitted and will be reviewed.");
      }
    } else {
      console.error("Registry commit failed:", error);
    }
  }, [currentUser, addSystemLog]);

  const handleAddStudent = useCallback(async (studentData: Partial<Student>) => {
    const { data, error } = await supabase.from('students').insert([studentData]).select();
    if (!error && data) {
      setAllStudents(prev => [data[0] as Student, ...prev]);
      addSystemLog(`New Subject Registered: ${data[0].lrn}`, 'Registry');
      return data[0];
    }
    return null;
  }, [addSystemLog]);

  const handleUpdateStatus = useCallback(async (id: string, status: Incident['status']) => {
    const { error } = await supabase.from('incidents').update({ status }).eq('id', id);
    if (!error) {
      setAllIncidents(prev => prev.map(inc => inc.id === id ? { ...inc, status } : inc));
      addSystemLog(`Incident ${id} updated to ${status}`, 'Audit');
    }
  }, [addSystemLog]);

  const renderContent = () => {
    if (!currentUser) return null;
    switch (activeTab) {
      case 'Dashboard': return <Dashboard incidents={filteredIncidents} students={filteredStudents} deviceLogs={deviceLogs} />;
      case 'Students': return <Students currentUser={currentUser} incidents={filteredIncidents} students={filteredStudents} searchQuery={searchQuery} parents={parents} deviceLogs={deviceLogs} onAddStudent={handleAddStudent} />;
      case 'Incidents': return <Incidents currentUser={currentUser} incidents={filteredIncidents} students={filteredStudents} incidentTypes={incidentTypes} onAddIncident={handleAddIncident} onUpdateStatus={handleUpdateStatus} searchQuery={searchQuery} />;
      case 'Interventions': return <Interventions currentUser={currentUser} students={filteredStudents} interventions={interventions} onAddIntervention={(data) => supabase.from('interventions').insert([data])} />;
      case 'Reports': return <Reports currentUser={currentUser} reports={reports} onGenerateReport={(data) => supabase.from('generated_reports').insert([data])} />;
      case 'System Logs': return <SystemLogs logs={systemLogs} />;
      case 'User Management': return <UserManagement localUsers={[]} onUpdateUser={(id, updates) => supabase.from('profiles').update(updates).eq('id', id)} onSync={fetchRegistryData} />;
      default: return <Dashboard incidents={filteredIncidents} students={filteredStudents} deviceLogs={deviceLogs} />;
    }
  };

  if (isInitializing) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-slate-50">
        <div className="text-center space-y-4">
          <Loader2 className="animate-spin text-slate-900 mx-auto" size={32} />
          <p className="text-[10px] font-black uppercase tracking-[0.3em] text-slate-400">Synchronizing Registry...</p>
        </div>
      </div>
    );
  }

  if (!currentUser) return <Login onLogin={setCurrentUser} onLocalBypass={() => {}} />;

  return (
    <Layout user={currentUser} activeTab={activeTab} setActiveTab={setActiveTab} onLogout={handleLogout} searchQuery={searchQuery} setSearchQuery={setSearchQuery} notifications={notifications} onMarkRead={() => {}}>
      {renderContent()}
    </Layout>
  );
};

export default App;

import React, { useMemo, useState, useRef } from 'react';
import { AlertTriangle, Plus, Eye, X, ShieldCheck, Mic, MicOff, Loader2, BrainCircuit, Shield, MessageSquare, History } from 'lucide-react';
import { User, Incident, Student, IncidentType } from '../types';
