import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { Loader2 } from 'lucide-react';
import Layout from './components/Layout';
import Dashboard from './pages/Dashboard';
import Students from './pages/Students';
import Incidents from './pages/Incidents';
import Interventions from './pages/Interventions';
import UserManagement from './pages/UserManagement';
import Reports from './pages/Reports';
import SystemLogs from './pages/SystemLogs';
import Login from './pages/Login';
import { User, Incident, Student, BehavioralIntervention, DeviceUsageRecord, ParentGuardian, GeneratedReport, Notification, SystemLog, IncidentType } from './types';
import { supabase } from './services/supabaseClient';
import { 
  MOCK_STUDENTS, MOCK_INCIDENTS, MOCK_INCIDENT_TYPES, 
  MOCK_INTERVENTIONS, MOCK_DEVICE_LOGS, MOCK_PARENTS, 
  MOCK_REPORTS, MOCK_SYSTEM_LOGS, MOCK_NOTIFICATIONS,
  MOCK_USERS
} from './constants';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState('Dashboard');
  const [isInitializing, setIsInitializing] = useState(true);

  const [allIncidents, setAllIncidents] = useState<Incident[]>([]);
  const [incidentTypes, setIncidentTypes] = useState<IncidentType[]>([]);
  const [allStudents, setAllStudents] = useState<Student[]>([]);
  const [interventions, setInterventions] = useState<BehavioralIntervention[]>([]);
  const [deviceLogs, setDeviceLogs] = useState<DeviceUsageRecord[]>([]);
  const [parents, setParents] = useState<ParentGuardian[]>([]);
  const [reports, setReports] = useState<GeneratedReport[]>([]);
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [systemLogs, setSystemLogs] = useState<SystemLog[]>([]);
  const [allUsers, setAllUsers] = useState<User[]>([]);
  const [searchQuery, setSearchQuery] = useState('');

  const isParent = currentUser?.role === 'Parent';

  // HELPER: Merge and de-duplicate records favoring Supabase data
  const mergeRecords = <T extends { id: string }>(mock: T[], live: T[]): T[] => {
    const map = new Map();
    mock.forEach(item => map.set(item.id, item));
    live.forEach(item => map.set(item.id, item));
    return Array.from(map.values());
  };

  const filteredStudents = useMemo(() => {
    const base = mergeRecords(MOCK_STUDENTS, allStudents);
    if (isParent && currentUser?.linked_lrn) {
      return base.filter(s => s.lrn === currentUser.linked_lrn || s.id.startsWith('mock-'));
    }
    return base;
  }, [currentUser, allStudents, isParent]);

  const filteredIncidents = useMemo(() => {
    const base = mergeRecords(MOCK_INCIDENTS, allIncidents);
    if (isParent && currentUser?.linked_lrn) {
      const student = filteredStudents.find(s => s.lrn === currentUser.linked_lrn);
      return base.filter(inc => inc.student_id === student?.id);
    }
    return base;
  }, [currentUser, allIncidents, filteredStudents, isParent]);

  const filteredInterventions = useMemo(() => {
    const base = mergeRecords(MOCK_INTERVENTIONS, interventions);
    if (isParent && currentUser?.linked_lrn) {
      const student = filteredStudents.find(s => s.lrn === currentUser.linked_lrn);
      return base.filter(int => int.student_id === student?.id);
    }
    return base;
  }, [currentUser, interventions, filteredStudents, isParent]);

  const addSystemLog = useCallback(async (action: string, category: SystemLog['category']) => {
    if (!currentUser) return;
    const newLog = {
      user_id: currentUser.id,
      user_name: currentUser.full_name,
      action,
      category,
      ip_address: 'System-Client',
      timestamp: new Date().toISOString()
    };

    try {
      await supabase.from('system_audit_logs').insert([newLog]);
    } catch (e) {}

    setSystemLogs(prev => [{ ...newLog, id: `sl-${Date.now()}` } as SystemLog, ...prev]);
  }, [currentUser]);

  const fetchRegistryData = useCallback(async () => {
    try {
      const [
        { data: studentsData },
        { data: incidentsData },
        { data: typesData },
        { data: interventionsData },
        { data: logsData },
        { data: parentsData },
        { data: reportsData },
        { data: sysLogsData },
        { data: notifsData },
        { data: profilesData }
      ] = await Promise.all([
        supabase.from('students').select('*'),
        supabase.from('incidents').select('*').order('date_reported', { ascending: false }),
        supabase.from('incident_types').select('*'),
        supabase.from('interventions').select('*').order('start_date', { ascending: false }),
        supabase.from('device_logs').select('*'),
        supabase.from('parents').select('*'),
        supabase.from('generated_reports').select('*'),
        supabase.from('system_audit_logs').select('*').order('timestamp', { ascending: false }),
        supabase.from('notifications').select('*').order('timestamp', { ascending: false }),
        supabase.from('profiles').select('*')
      ]);

      if (studentsData) setAllStudents(studentsData);
      if (incidentsData) setAllIncidents(incidentsData);
      setIncidentTypes(typesData || MOCK_INCIDENT_TYPES);
      if (interventionsData) setInterventions(interventionsData);
      setDeviceLogs(logsData || MOCK_DEVICE_LOGS);
      setParents(parentsData || MOCK_PARENTS);
      setReports(reportsData?.length ? reportsData : MOCK_REPORTS);
      setSystemLogs(sysLogsData?.length ? sysLogsData : MOCK_SYSTEM_LOGS);
      setNotifications(notifsData || MOCK_NOTIFICATIONS);
      setAllUsers(profilesData?.length ? profilesData : MOCK_USERS);
    } catch (err) {
      console.error("Critical: Registry synchronization failed.", err);
    } finally {
      setIsInitializing(false);
    }
  }, []);

  useEffect(() => {
    const checkUser = async () => {
      const { data: { session } } = await supabase.auth.getSession();
      if (session?.user) {
        const { data: profile } = await supabase.from('profiles').select('*').eq('id', session.user.id).single();
        if (profile) setCurrentUser(profile as User);
        else {
          setCurrentUser({
            id: session.user.id,
            full_name: session.user.user_metadata.full_name || 'Registry User',
            role: session.user.user_metadata.role || 'Teacher',
            email: session.user.email!,
            username: session.user.email!.split('@')[0],
            is_active: true,
            linked_lrn: session.user.user_metadata.linked_lrn
          });
        }
      }
      setIsInitializing(false);
    };
    checkUser();
  }, []);

  useEffect(() => {
    if (currentUser) {
      fetchRegistryData();
    }
  }, [currentUser, fetchRegistryData]);

  const handleLogout = async () => {
    await supabase.auth.signOut();
    setCurrentUser(null);
    setActiveTab('Dashboard');
  };

  const handleLrnSearch = (lrn: string) => {
    setSearchQuery(lrn);
    setActiveTab('Students');
  };

  const handleAddIncident = useCallback(async (newInc: Partial<Incident>) => {
    if (!currentUser) return;
    const incData = {
      student_id: newInc.student_id,
      reported_by_user_id: currentUser.id,
      incident_type_id: newInc.incident_type_id,
      date_reported: new Date().toISOString(),
      date_occurred: newInc.date_occurred || new Date().toISOString(),
      location: newInc.location,
      description: newInc.description,
      immediate_action: newInc.immediate_action || 'Registry Entry',
      status: 'Pending',
      is_parent_reported: isParent,
      is_anonymous: newInc.is_anonymous || false
    };

    const { data, error } = await supabase.from('incidents').insert([incData]).select();

    if (!error && data) {
      setAllIncidents(prev => [data[0] as Incident, ...prev]);
      addSystemLog(`Incident Registered: ${data[0].id}`, 'Registry');
    } else {
      setAllIncidents(prev => [{ ...incData, id: `temp-inc-${Date.now()}` } as Incident, ...prev]);
    }
  }, [currentUser, addSystemLog, isParent]);

  const handleAddStudent = useCallback(async (studentData: Partial<Student>) => {
    const { data, error } = await supabase.from('students').insert([studentData]).select();
    if (!error && data) {
      setAllStudents(prev => [data[0] as Student, ...prev]);
      addSystemLog(`New Subject Registered: ${data[0].lrn}`, 'Registry');
      return data[0];
    } else {
      const temp = { ...studentData, id: `temp-s-${Date.now()}` } as Student;
      setAllStudents(prev => [temp, ...prev]);
      return temp;
    }
  }, [addSystemLog]);

  const handleAddIntervention = useCallback(async (intData: Partial<BehavioralIntervention>) => {
    if (!currentUser) return;
    const payload = {
      ...intData,
      assigned_by_user_id: currentUser.id,
      start_date: new Date().toISOString(),
      status: 'Active',
      history: [
        { 
          id: `m-init-${Date.now()}`, 
          date: new Date().toISOString(), 
          title: 'Case Initialized', 
          notes: 'Dossier opened in the Registry.', 
          outcome: 'Plan active', 
          recorded_by: currentUser.full_name 
        }
      ]
    };

    const { data, error } = await supabase.from('interventions').insert([payload]).select();
    if (!error && data) {
      setInterventions(prev => [data[0] as BehavioralIntervention, ...prev]);
      addSystemLog(`Intervention Launched: ${data[0].id}`, 'Registry');
    } else {
      setInterventions(prev => [{ ...payload, id: `temp-int-${Date.now()}` } as BehavioralIntervention, ...prev]);
    }
  }, [currentUser, addSystemLog]);

  const handleUpdateStatus = useCallback(async (id: string, status: Incident['status']) => {
    const { error } = await supabase.from('incidents').update({ status }).eq('id', id);
    if (!error) {
      setAllIncidents(prev => prev.map(inc => inc.id === id ? { ...inc, status } : inc));
      addSystemLog(`Incident ${id} updated to ${status}`, 'Audit');
    } else {
      setAllIncidents(prev => prev.map(inc => inc.id === id ? { ...inc, status } : inc));
    }
  }, [addSystemLog]);

  const handleLocalBypass = () => {
    // Log in as System Admin for demo convenience
    setCurrentUser(MOCK_USERS[0]);
    setActiveTab('Dashboard');
  };

  const renderContent = () => {
    if (!currentUser) return null;
    switch (activeTab) {
      case 'Dashboard': 
        return <Dashboard 
          currentUser={currentUser} 
          incidents={filteredIncidents} 
          students={filteredStudents} 
          deviceLogs={deviceLogs} 
          onSearchLRN={handleLrnSearch} 
        />;
      case 'Students': 
        return <Students 
          currentUser={currentUser} 
          incidents={filteredIncidents} 
          students={filteredStudents} 
          searchQuery={searchQuery} 
          parents={parents} 
          deviceLogs={deviceLogs} 
          onAddStudent={handleAddStudent} 
        />;
      case 'Incidents': 
        return <Incidents 
          currentUser={currentUser} 
          incidents={filteredIncidents} 
          students={filteredStudents} 
          incidentTypes={incidentTypes} 
          onAddIncident={handleAddIncident} 
          onUpdateStatus={handleUpdateStatus} 
          searchQuery={searchQuery} 
        />;
      case 'Interventions': 
        return <Interventions 
          currentUser={currentUser} 
          students={filteredStudents} 
          interventions={filteredInterventions} 
          onAddIntervention={handleAddIntervention} 
        />;
      case 'Reports': 
        return <Reports 
          currentUser={currentUser} 
          reports={reports} 
          onGenerateReport={(data) => setReports(prev => [data, ...prev])} 
        />;
      case 'System Logs': 
        return <SystemLogs logs={systemLogs} />;
      case 'User Management': 
        return <UserManagement 
          localUsers={allUsers} 
          currentUser={currentUser} 
          onUpdateUser={(id, updates) => setAllUsers(prev => prev.map(u => u.id === id ? {...u, ...updates} : u))} 
          onSync={fetchRegistryData} 
        />;
      default: 
        return <Dashboard 
          currentUser={currentUser} 
          incidents={filteredIncidents} 
          students={filteredStudents} 
          deviceLogs={deviceLogs} 
          onSearchLRN={handleLrnSearch}
        />;
    }
  };

  if (isInitializing) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-slate-50">
        <div className="text-center space-y-4">
          <Loader2 className="animate-spin text-slate-900 mx-auto" size={32} />
          <p className="text-[10px] font-black uppercase tracking-[0.3em] text-slate-400">Bootstrapping Demo Registry...</p>
        </div>
      </div>
    );
  }

  if (!currentUser) return <Login onLogin={setCurrentUser} onLocalBypass={handleLocalBypass} />;

  return (
    <Layout user={currentUser} activeTab={activeTab} setActiveTab={setActiveTab} onLogout={handleLogout} searchQuery={searchQuery} setSearchQuery={setSearchQuery} notifications={notifications} onMarkRead={() => {}}>
      {renderContent()}
    </Layout>
  );
};

export default App;

import React, { useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { User } from '../types';
import { 
  Mail, Lock, ShieldCheck, User as UserIcon, 
  Briefcase, Loader2, Terminal, AlertTriangle, 
  ChevronDown, Eye, EyeOff, Search, Zap, ChevronRight,
  ArrowRight
} from 'lucide-react';
import { PREDEFINED_ACCOUNTS, MOCK_USERS } from '../constants';

interface LoginProps {
  onLogin: (user: User) => void;
  onLocalBypass: (user: User) => void;
}

const Login: React.FC<LoginProps> = ({ onLogin, onLocalBypass }) => {
  const [isLoginMode, setIsLoginMode] = useState(true);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [fullName, setFullName] = useState('');
  const [studentLrn, setStudentLrn] = useState('');
  const [role, setRole] = useState<'Teacher' | 'Counselor' | 'Parent'>('Teacher');
  const [error, setError] = useState('');
  const [isEmailLimitError, setIsEmailLimitError] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [showPassword, setShowPassword] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setError('');
    setIsEmailLimitError(false);

    try {
      if (isLoginMode) {
        // First check predefined for local quick login
        const predefined = PREDEFINED_ACCOUNTS.find(a => a.email === email && a.password === password);
        if (predefined) {
          onLogin(predefined.user as User);
          return;
        }

        const { data: authData, error: authError } = await supabase.auth.signInWithPassword({ email, password });
        if (authError) throw authError;

        if (authData.user) {
          const { data: profile } = await supabase.from('profiles').select('*').eq('id', authData.user.id).single();
          if (profile) {
            onLogin(profile as User);
          } else {
            onLogin({ 
              id: authData.user.id, 
              full_name: authData.user.user_metadata.full_name || 'Registry User', 
              role: authData.user.user_metadata.role || 'Teacher', 
              email: authData.user.email!, 
              username: authData.user.email!.split('@')[0], 
              is_active: true,
              linked_lrn: authData.user.user_metadata.linked_lrn
            } as User);
          }
        }
      } else {
        if (role === 'Parent' && studentLrn.length < 5) {
          throw new Error("A valid Student LRN is required for Parent registration.");
        }

        const { data: signUpData, error: signUpError } = await supabase.auth.signUp({
          email,
          password,
          options: { 
            data: { 
              full_name: fullName, 
              role: role,
              linked_lrn: role === 'Parent' ? studentLrn : null
            }
          }
        });

        if (signUpError) {
          if (signUpError.message.toLowerCase().includes("confirmation email") || signUpError.status === 429) {
            setIsEmailLimitError(true);
            throw new Error("Supabase email quota exceeded. The server cannot send more verification links this hour.");
          }
          throw signUpError;
        }

        if (signUpData.user) {
          await supabase.from('profiles').insert([{
            id: signUpData.user.id,
            full_name: fullName,
            role: role,
            email: email,
            username: email.split('@')[0],
            is_active: true,
            linked_lrn: role === 'Parent' ? studentLrn : null
          }]);

          alert("Verification email sent! Please confirm your email to activate your registry access.");
          setIsLoginMode(true);
        }
      }
    } catch (err: any) {
      setError(err.message || 'Verification system failure.');
    } finally {
      setIsLoading(false);
    }
  };

  const handleQuickLogin = (email: string) => {
    const account = PREDEFINED_ACCOUNTS.find(a => a.email === email);
    if (account) {
      onLogin(account.user as User);
    }
  };

  const triggerBypass = () => {
    onLocalBypass(MOCK_USERS[0]);
  };

  return (
    <div className="min-h-screen flex flex-col items-center justify-center bg-slate-50 relative overflow-hidden p-4">
      <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-teal-500 via-slate-900 to-teal-500"></div>

      <div className="w-full max-w-md relative z-10 space-y-6">
        <div className="bg-white rounded-2xl shadow-2xl border border-slate-200 overflow-hidden">
          <div className="px-6 py-2.5 bg-slate-900 flex items-center justify-between">
            <div className="flex items-center gap-2">
              <div className="w-2 h-2 rounded-full bg-teal-400 shadow-[0_0_8px_currentColor]"></div>
              <span className="text-[10px] font-black text-white/80 uppercase tracking-widest">Registry Secure</span>
            </div>
            <Terminal size={12} className="text-white/40" />
          </div>

          <div className="p-10 pb-6 text-center">
            <div className="w-16 h-16 bg-slate-900 rounded-2xl flex items-center justify-center text-white mx-auto mb-6 shadow-2xl ring-4 ring-slate-50">
              <ShieldCheck size={32} />
            </div>
            <h1 className="text-3xl font-bold text-slate-900 tracking-tight">SAFE-EDU</h1>
            <div className="mt-2 space-y-1">
              <p className="text-teal-600 text-[9px] font-black uppercase tracking-widest">Student Assistance & Fostering Excellence in EDUcation</p>
              <p className="text-slate-400 text-[8px] font-black uppercase tracking-[0.2em] opacity-80">Authority & Scholar Registry</p>
            </div>
          </div>

          <div className="px-10 flex border-b border-slate-100">
            <button onClick={() => { setIsLoginMode(true); setError(''); setIsEmailLimitError(false); }} className={`flex-1 py-4 text-[10px] font-black uppercase tracking-widest transition-all ${isLoginMode ? 'text-slate-900 border-b-2 border-slate-900' : 'text-slate-400 hover:text-slate-600'}`}>Sign In</button>
            <button onClick={() => { setIsLoginMode(false); setError(''); setIsEmailLimitError(false); }} className={`flex-1 py-4 text-[10px] font-black uppercase tracking-widest transition-all ${!isLoginMode ? 'text-slate-900 border-b-2 border-slate-900' : 'text-slate-400 hover:text-slate-600'}`}>Register</button>
          </div>

          <form onSubmit={handleSubmit} className="p-10 pt-8 pb-10 space-y-4">
            {error && (
              <div className="p-4 bg-red-50 text-red-700 text-[10px] font-bold uppercase rounded-xl border border-red-100 space-y-3 animate-in slide-in-from-top-2">
                <div className="flex items-center gap-2">
                  <AlertTriangle size={16} className="shrink-0 text-red-600" /> 
                  <span>{error}</span>
                </div>
                {isEmailLimitError && (
                  <button 
                    type="button"
                    onClick={triggerBypass}
                    className="w-full py-2.5 bg-red-600 text-white rounded-lg flex items-center justify-center gap-2 hover:bg-red-700 transition-colors shadow-sm"
                  >
                    <Zap size={12} fill="currentColor" />
                    <span>Bypass & Enter as Admin</span>
                    <ArrowRight size={12} />
                  </button>
                )}
              </div>
            )}

            <div className="space-y-4">
              {!isLoginMode && (
                <>
                  <div className="relative">
                    <UserIcon className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                    <input required type="text" value={fullName} onChange={(e) => setFullName(e.target.value)} className="w-full pl-10 pr-4 py-3.5 bg-slate-50 border border-slate-200 rounded-xl text-sm outline-none focus:ring-1 focus:ring-slate-900 font-medium" placeholder="Full Name" />
                  </div>
                  <div className="relative group">
                    <Briefcase className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" size={16} />
                    <select 
                      value={role} 
                      onChange={(e) => setRole(e.target.value as any)} 
                      className="w-full pl-10 pr-10 py-3.5 bg-slate-50 border border-slate-200 rounded-xl text-sm outline-none focus:ring-1 focus:ring-slate-900 appearance-none font-bold uppercase tracking-widest cursor-pointer"
                    >
                      <option value="Teacher">Teacher</option>
                      <option value="Counselor">Counselor</option>
                      <option value="Parent">Parent / Guardian</option>
                    </select>
                    <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" size={16} />
                  </div>
                  {role === 'Parent' && (
                    <div className="relative animate-in slide-in-from-top-2">
                      <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-teal-500" size={16} />
                      <input required type="text" value={studentLrn} onChange={(e) => setStudentLrn(e.target.value)} className="w-full pl-10 pr-4 py-3.5 bg-teal-50 border border-teal-200 rounded-xl text-sm outline-none focus:ring-1 focus:ring-teal-600 font-bold placeholder:text-teal-300" placeholder="Student LRN (Child's ID)" />
                    </div>
                  )}
                </>
              )}
              <div className="relative">
                <Mail className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                <input required type="email" value={email} onChange={(e) => setEmail(e.target.value)} className="w-full pl-10 pr-4 py-3.5 bg-slate-50 border border-slate-200 rounded-xl text-sm outline-none focus:ring-1 focus:ring-slate-900 font-medium" placeholder="Email Address" />
              </div>
              <div className="relative">
                <Lock className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                <input required type={showPassword ? "text" : "password"} value={password} onChange={(e) => setPassword(e.target.value)} className="w-full pl-10 pr-10 py-3.5 bg-slate-50 border border-slate-200 rounded-xl text-sm outline-none focus:ring-1 focus:ring-slate-900 font-medium" placeholder="Password" />
                <button type="button" onClick={() => setShowPassword(!showPassword)} className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 hover:text-slate-600 transition-colors">
                  {showPassword ? <EyeOff size={16} /> : <Eye size={16} />}
                </button>
              </div>
            </div>

            <button type="submit" disabled={isLoading} className="w-full py-4 bg-slate-900 text-white rounded-xl font-black text-[10px] uppercase shadow-2xl active:scale-95 disabled:opacity-70 transition-all hover:bg-slate-800 tracking-[0.2em]">
              {isLoading ? <Loader2 size={18} className="animate-spin mx-auto" /> : isLoginMode ? 'Authorize Session' : 'Create Authority Profile'}
            </button>
          </form>
        </div>

        {/* Demo Quick Access Panel */}
        <div className="bg-white/40 backdrop-blur-md rounded-2xl border border-white/60 p-6 shadow-xl animate-in fade-in slide-in-from-bottom-4 duration-700 delay-300">
          <div className="flex items-center gap-2 mb-4">
            <Zap size={14} className="text-amber-500 fill-amber-500" />
            <h3 className="text-[10px] font-black uppercase tracking-widest text-slate-500">Demo Quick Access (One-Click Bypass)</h3>
          </div>
          <div className="grid grid-cols-2 gap-3">
            <button onClick={() => handleQuickLogin('admin@gmail.com')} className="flex items-center justify-between p-3 bg-white border border-slate-200 rounded-xl hover:border-teal-500 hover:shadow-md transition-all group">
              <div className="text-left">
                <p className="text-[9px] font-black uppercase text-slate-400 tracking-tighter group-hover:text-teal-600">Admin Account</p>
                <p className="text-[11px] font-bold text-slate-800">System Master</p>
              </div>
              <ChevronRight size={14} className="text-slate-300 group-hover:text-teal-600" />
            </button>
            <button onClick={() => handleQuickLogin('teacher@gmail.com')} className="flex items-center justify-between p-3 bg-white border border-slate-200 rounded-xl hover:border-teal-500 hover:shadow-md transition-all group">
              <div className="text-left">
                <p className="text-[9px] font-black uppercase text-slate-400 tracking-tighter group-hover:text-teal-600">Teacher Account</p>
                <p className="text-[11px] font-bold text-slate-800">Sarah Teacher</p>
              </div>
              <ChevronRight size={14} className="text-slate-300 group-hover:text-teal-600" />
            </button>
            <button onClick={() => handleQuickLogin('counselor@gmail.com')} className="flex items-center justify-between p-3 bg-white border border-slate-200 rounded-xl hover:border-teal-500 hover:shadow-md transition-all group">
              <div className="text-left">
                <p className="text-[9px] font-black uppercase text-slate-400 tracking-tighter group-hover:text-teal-600">Counselor Account</p>
                <p className="text-[11px] font-bold text-slate-800">John Counselor</p>
              </div>
              <ChevronRight size={14} className="text-slate-300 group-hover:text-teal-600" />
            </button>
            <button onClick={() => handleQuickLogin('parent@gmail.com')} className="flex items-center justify-between p-3 bg-white border border-slate-200 rounded-xl hover:border-teal-500 hover:shadow-md transition-all group">
              <div className="text-left">
                <p className="text-[9px] font-black uppercase text-slate-400 tracking-tighter group-hover:text-teal-600">Parent Account</p>
